import{_ as t,o as a,c as r,aa as o}from"./chunks/framework.GPvTQ_Wl.js";const u=JSON.parse('{"title":"Consul scripts (reference)","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"reference/consul-scripts-reference.md","filePath":"reference/consul-scripts-reference.md","lastUpdated":1775689403000}'),n={name:"reference/consul-scripts-reference.md"};function i(s,e,c,l,d,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="consul-scripts-reference" tabindex="-1">Consul scripts (reference) <a class="header-anchor" href="#consul-scripts-reference" aria-label="Permalink to &quot;Consul scripts (reference)&quot;">​</a></h1><p>This page lists all built-in scripts available from the <strong>Consul</strong> tab.</p><h4 id="ad-rebellos-—-spawns-rebellion" tabindex="-1">Ad Rebellos — Spawns rebellion <a class="header-anchor" href="#ad-rebellos-—-spawns-rebellion" aria-label="Permalink to &quot;Ad Rebellos — Spawns rebellion&quot;">​</a></h4><p><strong>ID</strong>: <code>consul_adrebellos_entry</code><br> When activated, any settlement you click on will trigger a rebellion.</p><h4 id="adice-provinciam-—-transfer-settlement" tabindex="-1">Adice Provinciam — Transfer settlement <a class="header-anchor" href="#adice-provinciam-—-transfer-settlement" aria-label="Permalink to &quot;Adice Provinciam — Transfer settlement&quot;">​</a></h4><p><strong>ID</strong>: <code>consul_transfersettlement_entry</code><br> When activated, first click on the settlement you want to transfer, either from the campaign map or strategic view. Then click on the target settlement or character to which you want to transfer it.</p><h4 id="casus-belli-—-force-war" tabindex="-1">Casus Belli — Force war <a class="header-anchor" href="#casus-belli-—-force-war" aria-label="Permalink to &quot;Casus Belli — Force war&quot;">​</a></h4><p><strong>ID</strong>: <code>consul_force_make_war_entry</code><br> When activated, first click on a settlement/character to select the first faction, then click on another settlement/character to select the second faction to make war.</p><h4 id="custodes-vocati-—-exchange-garrison" tabindex="-1">Custodes Vocati — Exchange garrison <a class="header-anchor" href="#custodes-vocati-—-exchange-garrison" aria-label="Permalink to &quot;Custodes Vocati — Exchange garrison&quot;">​</a></h4><p><strong>ID</strong>: <code>consul_force_exchange_garrison_entry</code><br> To mobilize a garrison for field duty, first select your general&#39;s army. Then, designate the settlement with which to exchange forces. Important: Your general must be outside of a settlement for this function to work correctly.</p><h4 id="exterminare-—-kill-character" tabindex="-1">Exterminare — Kill character <a class="header-anchor" href="#exterminare-—-kill-character" aria-label="Permalink to &quot;Exterminare — Kill character&quot;">​</a></h4><p><strong>ID</strong>: <code>consul_exterminare_entry</code><br> When activated, any character you select will be exterminated.</p><h4 id="impetus-—-restore-action-points" tabindex="-1">Impetus — Restore action points <a class="header-anchor" href="#impetus-—-restore-action-points" aria-label="Permalink to &quot;Impetus — Restore action points&quot;">​</a></h4><p><strong>ID</strong>: <code>consul_replenish_action_points_entry</code><br> Impetus: Click on a character to grant them a surge of momentum, fully restoring their action points for the turn.</p><h4 id="incrementum-—-add-growth-point" tabindex="-1">Incrementum — Add growth point <a class="header-anchor" href="#incrementum-—-add-growth-point" aria-label="Permalink to &quot;Incrementum — Add growth point&quot;">​</a></h4><p><strong>ID</strong>: <code>consul_incrementum_regio_entry</code><br> To unlock a province potential for future expansion, select this command and then click on a settlement. This represents a strategic state investment in land surveying and administrative reform, permanently granting the region +1 Growth Point. This point is required to open up new building slots, allowing for greater development.</p><h4 id="pax-aeterna-—-force-peace" tabindex="-1">Pax Aeterna — Force peace <a class="header-anchor" href="#pax-aeterna-—-force-peace" aria-label="Permalink to &quot;Pax Aeterna — Force peace&quot;">​</a></h4><p><strong>ID</strong>: <code>consul_force_make_peace_entry</code><br> When activated, first click on a settlement/character to select the first faction, then click on another settlement/character to select the second faction to make peace.</p><h4 id="sedatio-—-boost-public-order" tabindex="-1">Sedatio — Boost public order <a class="header-anchor" href="#sedatio-—-boost-public-order" aria-label="Permalink to &quot;Sedatio — Boost public order&quot;">​</a></h4><p><strong>ID</strong>: <code>consul_sedatio_provinciae_entry</code><br> To calm unrest and bolster loyalty, select this command and then click on a settlement. This will temporarily appease the populace, providing a significant (+10) boost to public order across the entire province. Use it to stabilize newly conquered or rebellious lands.</p><h4 id="subiugatio-—-force-vassalage" tabindex="-1">Subiugatio — Force vassalage <a class="header-anchor" href="#subiugatio-—-force-vassalage" aria-label="Permalink to &quot;Subiugatio — Force vassalage&quot;">​</a></h4><p><strong>ID</strong>: <code>consul_force_make_vassal_entry</code><br> When activated, click on the character/settlement you want to subjugate, then click on the character/settlement recipient</p><h4 id="vexatio-—-penalize-public-order" tabindex="-1">Vexatio — Penalize public order <a class="header-anchor" href="#vexatio-—-penalize-public-order" aria-label="Permalink to &quot;Vexatio — Penalize public order&quot;">​</a></h4><p><strong>ID</strong>: <code>consul_vexatio_provinciae_entry</code><br> To make an example of a province or suppress dissent, select this command and then click on a settlement. This will enact a policy of official harassment, such as punitive levies or forced quartering of troops, inflicting a severe (-10) penalty to public order.</p>',24)])])}const m=t(n,[["render",i]]);export{u as __pageData,m as default};
